external_knowledge:
- 'most popular menu items' refers to the top-selling items by category, ranked by the total quantity sold; 
- 'top nutritional trends' refers to the nutritional information of the most popular menu items; 
- 'users who frequently access the system' refers to the top 5 users with the highest number of access logs; 
- 'highest activity levels' refers to the users with the highest access counts.

sql:
SELECT menu_item_id
FROM sales_data
ORDER BY quantity_sold DESC;

SELECT COUNT(update_id) AS total_updates
FROM menu_item_updates
WHERE menu_item_id = 1;
